1	// By default, the following three modules take one or two 18-bit signed inputs,
2	// and produce a 22-bit signed output in a single clock cycle.
3	// Scaling comments assume each number is interpreted as in the range [-1:1],
4	
5	// multiply
6	// r = a * b / 2
7	// Internally, expect to use 18-bit signed inputs to the hardware multiplier,
8	// matching the capabilities of Xilinx, Altera, Lattice, and Gowin chips.
9	// Configuring for 24-bit signed multiplication still works OK with Xilinx
10	// DSP48E1 and Vivado, where it combines two 18x25 multipliers and still
11	// makes reasonable timing.
12	module sf_mul #(
13		parameter dw=18,
14		parameter mw=18
15	) (
16		input clk,
17		input ce,  // clock enable
18		// input ports
19		input signed [dw-1:0] a,
20		input signed [dw-1:0] b,
21		// result ports
22		output [dw+3:0] r
23	);
24	
25	reg signed [2*mw-1:0] r1;  // full 36-bit result
26	wire signed [mw-1:0] a_trunc = a[dw-1:dw-mw];
27	wire signed [mw-1:0] b_trunc = b[dw-1:dw-mw];
28	always @(posedge clk) if (ce) begin
29		r1 <= a_trunc * b_trunc;
30	end
31	assign r = r1[2*mw-1:2*mw-4-dw];
32	endmodule
33	
34	// add or subtract
35	// r = (a +/- b) / 2
36	module sf_add #(
37		parameter dw=18
38	) (
39		input clk,
40		input ce,  // clock enable
41		// input ports
42		input signed [dw-1:0] a,
43		input signed [dw-1:0] b,
44		input sub,
45		// result ports
46		output [dw+3:0] r
47	);
48	
49	reg signed [dw:0] r1;
50	always @(posedge clk) if (ce) begin
51		r1 <= sub ? (a-b) : (a+b);
52	end
53	assign r = {r1[dw],r1,2'b0};
54	endmodule
55	
56	// approximate inverse, to start iterative refinement
57	// (1/a) / 256
58	// See inver1.py for supporting theory,
59	// and cgen_lib.py function full_inv for iteration rule
60	module sf_inv #(
61		parameter dw=18
62	) (
63		input clk,
64		input ce,  // clock enable
65		// input ports
66		input signed [dw-1:0] a,
67		// output ports
68		output [dw+3:0] r
69	);
70	
71	localparam iscale = 9;  // number of non-sign bits to use in LUT
72	wire [iscale-1:0] abs_a = a[dw-1] ? ~a[dw-2:dw-1-iscale] : a[dw-2:dw-1-iscale];
73	reg [iscale:0] r1=0;
74	reg sign_a=0;
75	always @(posedge clk) if (ce) begin
76		sign_a <= a[dw-1];
77		casez (abs_a)
78		// positive numbers
79		//  r=min(floor(16./[0:15]*16/4+0.5),15);
80		//  printf('\t%d: r1 <= %d;\n',[[0:15]; r])
81		// 2.^(-floor(log2([0:255]/256))-1)
82		// In theory can be parameterized with a for loop;
83		// this version hard-coded for the case iscale == 8.
84		9'b11???????: r1 <= 2;
85		9'b10???????: r1 <= 3;
86		9'b011??????: r1 <= 4;
87		9'b010??????: r1 <= 6;
88		9'b0011?????: r1 <= 8;
89		9'b0010?????: r1 <= 12;
90		9'b00011????: r1 <= 16;
91		9'b00010????: r1 <= 24;
92		9'b000011???: r1 <= 32;
93		9'b000010???: r1 <= 48;
94		9'b0000011??: r1 <= 64;
95		9'b0000010??: r1 <= 96;
96		9'b00000011?: r1 <= 128;
97		9'b00000010?: r1 <= 192;
98		9'b000000011: r1 <= 256;
99		9'b000000010: r1 <= 384;
100		9'b000000001: r1 <= 512;
101		9'b000000000: r1 <= 1023;
102		endcase
103	end
104	assign r = {sign_a, (sign_a ? ~r1 : r1), {(dw+4-iscale-2){sign_a}}};
105	//  (1 + (iscale+1) + (dw+4-iscale-2) = dw+4
106	endmodule
107	
108	// put the above modules together, with saturating shifter
109	// Now the output width matches the input width of 18 bits
110	module sf_alu #(
111		parameter dw=18,
112		parameter mw=18  // see sf_mul
113	) (
114		input clk,
115		input ce,  // clock enable
116		// input ports
117		input signed [dw-1:0] a,
118		input signed [dw-1:0] b,
119		input [2:0] op,
120		input [1:0] sv,
121		// result ports
122		output signed [dw-1:0] r,
123		output valid_o,
124		output sat_happened
125	);
126	
127	reg vo_mul=0, vo_add=0, vo_inv=0;
128	always @(posedge clk) if (ce) begin
129		vo_mul <= op==4;
130		vo_add <= op[2:1]==3;
131		vo_inv <= op==5;
132	end
133	wire signed [dw+3:0] r_mul, r_add, r_inv;
134	sf_mul #(.dw(dw), .mw(mw)) mul(.clk(clk), .ce(ce), .a(a), .b(b),              .r(r_mul));
135	sf_add #(.dw(dw)) add(.clk(clk), .ce(ce), .a(a), .b(b), .sub(op[0]), .r(r_add));
136	sf_inv #(.dw(dw)) inv(.clk(clk), .ce(ce), .a(a),                     .r(r_inv));
137	
138	reg valid_s=0, valid_r=0;
139	reg signed [dw+3:0] shf;
140	reg signed [dw-1:0] sat;
141	wire signed [dw+3:0] mux = vo_mul ? r_mul : vo_add ? r_add : r_inv;
142	reg sat_happened_r=0;
143	always @(posedge clk) if (ce) begin
144		// multiplexer and shifter
145		valid_s <= vo_mul|vo_add|vo_inv;
146		case (sv)
147			0: shf <= {{3{mux[dw+3]}},mux[dw+3:3]};
148			1: shf <= {{2{mux[dw+3]}},mux[dw+3:2]};
149			2: shf <= {{1{mux[dw+3]}},mux[dw+3:1]};
150			3: shf <= {            mux      };
151		endcase
152		// saturater
153		valid_r <= valid_s;
154	`define UNSAT(x,old,new) (~|x[old:new] | &x[old:new])
155	`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
156		sat <= `SAT(shf,dw+3,dw-1);
157		sat_happened_r <= ~`UNSAT(shf,dw+3,dw-1);
158	end
159	assign r = sat;
160	assign valid_o = valid_r;
161	assign sat_happened = valid_r & sat_happened_r;
162	
163	`undef SAT
164	`undef UNSAT
165	
166	endmodule
167	
168	// ALU and register file, no instruction sequencing
169	module sf_main #(
170		parameter pw = 18,  // port width
171		parameter extra = 4,  // extra guard bits that appear in registers and some arithmetic, but maybe not multiplier inputs
172		parameter mw = 18  // multiplier width, see sf_mul
173	) (
174		input clk,
175		input ce,  // clock enable
176		input [20:0] inst,  // consumes 21 bits of instruction per cycle
177		input signed [pw-1:0] meas,  // measurements from radio
178		// Results
179		output                 ab_update,
180		output signed [pw-1:0] a_o,
181		output signed [pw-1:0] b_o,
182		output                 cd_update,
183		output signed [pw-1:0] c_o,
184		output signed [pw-1:0] d_o,
185		// Monitoring only, probably superfluous
186		output signed [pw+extra-1:0] trace,
187		output collide_o,
188		output stray_o,
189		output discard_o,
190		output sat_happened
191	);
192	
193	// Instruction word "decoding"
194	// Controller should set wa and set during cycles when meas comes in.
195	//  op
196	//   0  NOP
197	//   1  write results to external hardware (a_o, b_o)
198	//   2  write results to external hardware (c_o, d_o)
199	//   3  -
200	//   4  mul
201	//   5  inv
202	//   6  add
203	//   7  sub
204	// Pipelining is very simple:
205	//  cycle  valid fields    name
206	//    1   ra_a,  ra_b     read
207	//    2   op              operate
208	//    3   sv              mux/shift
209	//    4   -               saturate
210	//    5   wa              writeback
211	// The new value of a destination register is first readable at cycle 6.
212	// The collision detection logic is completely superfluous.
213	// The stray and discard logic is mostly superfluous.
214	wire [4:0] ra_a = inst[4:0];
215	wire [4:0] ra_b = inst[9:5];
216	wire [4:0] wa = inst[14:10];
217	wire [2:0] op = inst[17:15];
218	wire [1:0] sv = inst[19:18];
219	wire       set = inst[20];
220	
221	localparam dw = pw + extra;
222	integer scale = 1 << extra; // Not used here, but helps test bench display numbers properly
223	
224	// Register file: one writer, two readers
225	wire signed [dw-1:0] alu_out;
226	wire signed [dw-1:0] d_in = set ? {meas,{extra{1'b0}}} : alu_out;
227	wire we_a;
228	wire we = we_a | set;
229	wire wa_zero = ~(|wa);
230	(* ram_style = "distributed" *) reg signed [dw-1:0] rf_a [31:0];
231	(* ram_style = "distributed" *) reg signed [dw-1:0] rf_b [31:0];
232	reg signed [dw-1:0] a=0, b=0;
233	always @(posedge clk) if (ce) begin
234		if (we) rf_a[wa] <= d_in;
235		if (we) rf_b[wa] <= d_in;
236		a <= rf_a[ra_a];
237		b <= rf_b[ra_b];
238	end
239	
240	sf_alu #(.dw(dw), .mw(mw)) alu(.clk(clk), .ce(ce), .a(a), .b(b), .op(op), .sv(sv),
241		.r(alu_out), .valid_o(we_a),
242		.sat_happened(sat_happened));
243	
244	// make values available to outside world
245	// take most significant bits
246	reg signed [pw-1:0] a_out=0, b_out=0;
247	reg ab_u=0;
248	always @(posedge clk) if (ce & (op==1)) begin
249		a_out <= a[dw-1:extra];
250		b_out <= b[dw-1:extra];
251		ab_u <= 1;
252	end else ab_u <= 0;
253	assign a_o = a_out;
254	assign b_o = b_out;
255	assign ab_update = ab_u;
256	
257	// make values available to outside world
258	// take most significant bits
259	reg signed [pw-1:0] c_out=0, d_out=0;
260	reg cd_u=0;
261	always @(posedge clk) if (ce & (op==2)) begin
262		c_out <= a[dw-1:extra];
263		d_out <= b[dw-1:extra];
264		cd_u <= 1;
265	end else cd_u <= 0;
266	assign c_o = c_out;
267	assign d_o = d_out;
268	assign cd_update = cd_u;
269	
270	assign trace = d_in;
271	assign collide_o = we_a & set;
272	assign stray_o = ~wa_zero & ~we;
273	assign discard_o = wa_zero & we;
274	endmodule
