// By default, the following three modules take one or two 18-bit signed inputs,
// and produce a 22-bit signed output in a single clock cycle.
// Scaling comments assume each number is interpreted as in the range [-1:1],

// multiply
// r = a * b / 2
// Internally, expect to use 18-bit signed inputs to the hardware multiplier,
// matching the capabilities of Xilinx, Altera, Lattice, and Gowin chips.
// Configuring for 24-bit signed multiplication still works OK with Xilinx
// DSP48E1 and Vivado, where it combines two 18x25 multipliers and still
// makes reasonable timing.
module sf_mul #(
	parameter dw=18,
	parameter mw=18
) (
	input clk,
	input ce,  // clock enable
	// input ports
	input signed [dw-1:0] a,
	input signed [dw-1:0] b,
	// result ports
	output [dw+3:0] r
);

reg signed [2*mw-1:0] r1;  // full 36-bit result
wire signed [mw-1:0] a_trunc = a[dw-1:dw-mw];
wire signed [mw-1:0] b_trunc = b[dw-1:dw-mw];
always @(posedge clk) if (ce) begin
	r1 <= a_trunc * b_trunc;
end
assign r = r1[2*mw-1:2*mw-4-dw];
endmodule

// add or subtract
// r = (a +/- b) / 2
module sf_add #(
	parameter dw=18
) (
	input clk,
	input ce,  // clock enable
	// input ports
	input signed [dw-1:0] a,
	input signed [dw-1:0] b,
	input sub,
	// result ports
	output [dw+3:0] r
);

reg signed [dw:0] r1;
always @(posedge clk) if (ce) begin
	r1 <= sub ? (a-b) : (a+b);
end
assign r = {r1[dw],r1,2'b0};
endmodule

// approximate inverse, to start iterative refinement
// (1/a) / 256
// See inver1.py for supporting theory,
// and cgen_lib.py function full_inv for iteration rule
module sf_inv #(
	parameter dw=18
) (
	input clk,
	input ce,  // clock enable
	// input ports
	input signed [dw-1:0] a,
	// output ports
	output [dw+3:0] r
);

localparam iscale = 9;  // number of non-sign bits to use in LUT
wire [iscale-1:0] abs_a = a[dw-1] ? ~a[dw-2:dw-1-iscale] : a[dw-2:dw-1-iscale];
reg [iscale:0] r1=0;
reg sign_a=0;
always @(posedge clk) if (ce) begin
	sign_a <= a[dw-1];
	casez (abs_a)
	// positive numbers
	//  r=min(floor(16./[0:15]*16/4+0.5),15);
	//  printf('\t%d: r1 <= %d;\n',[[0:15]; r])
	// 2.^(-floor(log2([0:255]/256))-1)
	// In theory can be parameterized with a for loop;
	// this version hard-coded for the case iscale == 8.
	9'b11???????: r1 <= 2;
	9'b10???????: r1 <= 3;
	9'b011??????: r1 <= 4;
	9'b010??????: r1 <= 6;
	9'b0011?????: r1 <= 8;
	9'b0010?????: r1 <= 12;
	9'b00011????: r1 <= 16;
	9'b00010????: r1 <= 24;
	9'b000011???: r1 <= 32;
	9'b000010???: r1 <= 48;
	9'b0000011??: r1 <= 64;
	9'b0000010??: r1 <= 96;
	9'b00000011?: r1 <= 128;
	9'b00000010?: r1 <= 192;
	9'b000000011: r1 <= 256;
	9'b000000010: r1 <= 384;
	9'b000000001: r1 <= 512;
	9'b000000000: r1 <= 1023;
	endcase
end
assign r = {sign_a, (sign_a ? ~r1 : r1), {(dw+4-iscale-2){sign_a}}};
//  (1 + (iscale+1) + (dw+4-iscale-2) = dw+4
endmodule

// put the above modules together, with saturating shifter
// Now the output width matches the input width of 18 bits
module sf_alu #(
	parameter dw=18,
	parameter mw=18  // see sf_mul
) (
	input clk,
	input ce,  // clock enable
	// input ports
	input signed [dw-1:0] a,
	input signed [dw-1:0] b,
	input [2:0] op,
	input [1:0] sv,
	// result ports
	output signed [dw-1:0] r,
	output valid_o,
	output sat_happened
);

reg vo_mul=0, vo_add=0, vo_inv=0;
always @(posedge clk) if (ce) begin
	vo_mul <= op==4;
	vo_add <= op[2:1]==3;
	vo_inv <= op==5;
end
wire signed [dw+3:0] r_mul, r_add, r_inv;
sf_mul #(.dw(dw), .mw(mw)) mul(.clk(clk), .ce(ce), .a(a), .b(b),              .r(r_mul));
sf_add #(.dw(dw)) add(.clk(clk), .ce(ce), .a(a), .b(b), .sub(op[0]), .r(r_add));
sf_inv #(.dw(dw)) inv(.clk(clk), .ce(ce), .a(a),                     .r(r_inv));

reg valid_s=0, valid_r=0;
reg signed [dw+3:0] shf;
reg signed [dw-1:0] sat;
wire signed [dw+3:0] mux = vo_mul ? r_mul : vo_add ? r_add : r_inv;
reg sat_happened_r=0;
always @(posedge clk) if (ce) begin
	// multiplexer and shifter
	valid_s <= vo_mul|vo_add|vo_inv;
	case (sv)
		0: shf <= {{3{mux[dw+3]}},mux[dw+3:3]};
		1: shf <= {{2{mux[dw+3]}},mux[dw+3:2]};
		2: shf <= {{1{mux[dw+3]}},mux[dw+3:1]};
		3: shf <= {            mux      };
	endcase
	// saturater
	valid_r <= valid_s;
`define UNSAT(x,old,new) (~|x[old:new] | &x[old:new])
`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
	sat <= `SAT(shf,dw+3,dw-1);
	sat_happened_r <= ~`UNSAT(shf,dw+3,dw-1);
end
assign r = sat;
assign valid_o = valid_r;
assign sat_happened = valid_r & sat_happened_r;

`undef SAT
`undef UNSAT

endmodule

// ALU and register file, no instruction sequencing
module sf_main #(
	parameter pw = 18,  // port width
	parameter extra = 4,  // extra guard bits that appear in registers and some arithmetic, but maybe not multiplier inputs
	parameter mw = 18  // multiplier width, see sf_mul
) (
	input clk,
	input ce,  // clock enable
	input [20:0] inst,  // consumes 21 bits of instruction per cycle
	input signed [pw-1:0] meas,  // measurements from radio
	// Results
	output                 ab_update,
	output signed [pw-1:0] a_o,
	output signed [pw-1:0] b_o,
	output                 cd_update,
	output signed [pw-1:0] c_o,
	output signed [pw-1:0] d_o,
	// Monitoring only, probably superfluous
	output signed [pw+extra-1:0] trace,
	output collide_o,
	output stray_o,
	output discard_o,
	output sat_happened
);

// Instruction word "decoding"
// Controller should set wa and set during cycles when meas comes in.
//  op
//   0  NOP
//   1  write results to external hardware (a_o, b_o)
//   2  write results to external hardware (c_o, d_o)
//   3  -
//   4  mul
//   5  inv
//   6  add
//   7  sub
// Pipelining is very simple:
//  cycle  valid fields    name
//    1   ra_a,  ra_b     read
//    2   op              operate
//    3   sv              mux/shift
//    4   -               saturate
//    5   wa              writeback
// The new value of a destination register is first readable at cycle 6.
// The collision detection logic is completely superfluous.
// The stray and discard logic is mostly superfluous.
wire [4:0] ra_a = inst[4:0];
wire [4:0] ra_b = inst[9:5];
wire [4:0] wa = inst[14:10];
wire [2:0] op = inst[17:15];
wire [1:0] sv = inst[19:18];
wire       set = inst[20];

localparam dw = pw + extra;
integer scale = 1 << extra; // Not used here, but helps test bench display numbers properly

// Register file: one writer, two readers
wire signed [dw-1:0] alu_out;
wire signed [dw-1:0] d_in = set ? {meas,{extra{1'b0}}} : alu_out;
wire we_a;
wire we = we_a | set;
wire wa_zero = ~(|wa);
(* ram_style = "distributed" *) reg signed [dw-1:0] rf_a [31:0];
(* ram_style = "distributed" *) reg signed [dw-1:0] rf_b [31:0];
reg signed [dw-1:0] a=0, b=0;
always @(posedge clk) if (ce) begin
	if (we) rf_a[wa] <= d_in;
	if (we) rf_b[wa] <= d_in;
	a <= rf_a[ra_a];
	b <= rf_b[ra_b];
end

sf_alu #(.dw(dw), .mw(mw)) alu(.clk(clk), .ce(ce), .a(a), .b(b), .op(op), .sv(sv),
	.r(alu_out), .valid_o(we_a),
	.sat_happened(sat_happened));

// make values available to outside world
// take most significant bits
reg signed [pw-1:0] a_out=0, b_out=0;
reg ab_u=0;
always @(posedge clk) if (ce & (op==1)) begin
	a_out <= a[dw-1:extra];
	b_out <= b[dw-1:extra];
	ab_u <= 1;
end else ab_u <= 0;
assign a_o = a_out;
assign b_o = b_out;
assign ab_update = ab_u;

// make values available to outside world
// take most significant bits
reg signed [pw-1:0] c_out=0, d_out=0;
reg cd_u=0;
always @(posedge clk) if (ce & (op==2)) begin
	c_out <= a[dw-1:extra];
	d_out <= b[dw-1:extra];
	cd_u <= 1;
end else cd_u <= 0;
assign c_o = c_out;
assign d_o = d_out;
assign cd_update = cd_u;

assign trace = d_in;
assign collide_o = we_a & set;
assign stray_o = ~wa_zero & ~we;
assign discard_o = wa_zero & we;
endmodule

module sf_user #(
	parameter pw = 18,  // port width
	parameter extra = 4,  // see sf_main
	parameter mw = 18,  // multiplier width, pw + extra >= mw
	parameter data_len = 6,
	parameter consts_len = 4,
	parameter const_aw = 2
) (
	input clk,
	input ce,  // clock enable
	input signed [pw-1:0] meas,  // measurements from radio
	input trigger,   // high for one cycle, just before meas stream starts
	// Interface to external parameter storage
	(* external *)
	output [const_aw-1:0] h_addr, // external address for param memory
	(* external *)
	input signed [pw-1:0] h_data, // external
	// Results
	output                 ab_update,
	output signed [pw-1:0] a_o,
	output signed [pw-1:0] b_o,
	output                 cd_update,
	output signed [pw-1:0] c_o,
	output signed [pw-1:0] d_o,
	// Debug output
	output signed [pw+extra-1:0] trace,
	output [6:0] trace_addr,
	output trace_strobe,
	output [6:0] sat_count
);

// PC stalls at 127, resets to 0 on trigger
reg [6:0] pc=127;
wire step=~(&pc);
reg run=0, run1=0;
always @(posedge clk) if (ce) begin
	pc <= trigger ? 0 : pc + step;
	if (~step) run <= 0;
	if (trigger) run <= 1;
	run1 <= run;
end
assign trace_strobe = run1;

assign h_addr = pc + 1 - data_len;

// Measurements stream in during first data_len cycles,
// host-settable parameters during next consts_len cycles.
wire choose_const = pc>=data_len && pc<(data_len+consts_len);
reg signed [pw-1:0] meas_mux=0;
always @(posedge clk) if (ce) meas_mux <= choose_const ? h_data : meas;

// Create the instruction ROM, using generated code.
// It would be easy to make this memory writable, but I don't
// think I will want to change the program at run time.
(* rom_style = "distributed" *) reg [20:0] inst;
always @(posedge clk) if (ce) case (pc)
`include "ops.vh"
endcase

// reg [20:0] inst1=0;
// always @(posedge clk) if (ce) inst1 <= inst;  // pipeline for speed with S3 BRAM

// Instantiate the compute engine
wire sat_happened;
sf_main #(.pw(pw), .extra(extra), .mw(mw)) cpu(.clk(clk), .ce(ce),
	.inst(inst), .meas(meas_mux),
	.ab_update(ab_update),
	.a_o(a_o), .b_o(b_o),
	.cd_update(cd_update),
	.c_o(c_o), .d_o(d_o),
	.trace(trace), .sat_happened(sat_happened));

// Count saturation events
reg [6:0] sat_cnt=0, sat_report=0;
always @(posedge clk) if (ce) begin
	sat_cnt <= trigger ? 0 : sat_cnt + sat_happened;
	if (trigger) sat_report <= sat_cnt;
end
assign sat_count = sat_report;
assign trace_addr = pc;

endmodule

// ------------------------------------
// SF_USER_WRAP
// Convenience wrapper over sf_user, allowing its parameters to be set via:
// - Memory interface (sf_user_pmem)
// - Parallel register interface (sf_user_preg)
//
// Care must be taken when updating parameters while data is flowing as it
// may result in sf_user sampling an incoherent parameter set and producing
// incorrect results. Examples of such situations are:
// - When using the memory interface, the parameter set can't be updated atomically
// - The use of distinct host_clk and sf_clk domains may lead to temporary
//   meta-stability affecting the reading of the parameters
//
// It is up to the user to prevent or mitigate these scenarios.
//
// ------------------------------------

`define SF_USER_PARAM parameter pw = 18,\
                      parameter extra = 4,\
                      parameter mw = 18,\
                      parameter data_len = 6,\
                      parameter consts_len = 4,\
                      parameter const_aw = 2

`define SF_USER_PORTS input sf_clk,\
                      input ce,\
                      input signed [pw-1:0] meas,\
                      input trigger,\
                      output                 ab_update,\
                      output signed [pw-1:0] a_o,\
                      output signed [pw-1:0] b_o,\
                      output                 cd_update,\
                      output signed [pw-1:0] c_o,\
                      output signed [pw-1:0] d_o,\
                      output signed [pw+extra-1:0] trace,\
                      output [6:0] trace_addr,\
                      output trace_strobe,\
                      output [6:0] sat_count,

module sf_user_pmem #(
        `SF_USER_PARAM
) (
        `SF_USER_PORTS
        // Host port to set parameters in DPRAM
        input                 h_clk,
        input                 h_write,
        input  [const_aw-1:0] h_addr,
        input signed [pw-1:0] h_data
);

wire signed [pw-1:0]       rd_data;
wire        [const_aw-1:0] rd_addr;

// DPRAM written by the host, read by the state machine
sf_dpram #(.aw(const_aw), .dw(pw)) i_const_mem (
        .clka(h_clk), .clkb(sf_clk),
        .addra(h_addr), .dina(h_data), .wena(ce & h_write),
        .addrb(rd_addr), .doutb(rd_data));

sf_user #(.pw(pw), .extra(extra), .mw(mw), .data_len(data_len),
        .consts_len(consts_len), .const_aw(const_aw))
sf_user (
        .clk(sf_clk), .ce(ce), .meas(meas), .trigger(trigger),
        .h_addr(rd_addr), .h_data(rd_data),
        .ab_update(ab_update), .a_o(a_o), .b_o(b_o),
        .cd_update(cd_update), .c_o(c_o), .d_o(d_o),
        .trace(trace), .trace_addr(trace_addr), .trace_strobe(trace_strobe),
        .sat_count(sat_count));

endmodule


module sf_user_preg #(
        `SF_USER_PARAM
) (
        `SF_USER_PORTS
        // Flattened input to parameter register bank
        input [pw*consts_len-1:0] param_in
);

wire signed [pw-1:0]       rd_data;
wire        [const_aw-1:0] rd_addr;
reg         [pw-1:0]       p_regbank[consts_len-1:0];

// Register bank written by the host, read by state machine.
// Input parameters (param_in) might come from a different clock domain;
// this assumes that the parameters are quasi-static and can be simply
// re-timed in the sf_clk domain
genvar r;
generate for (r=0; r<consts_len; r=r+1) begin : G_P_REGBANK
        always @(posedge sf_clk) begin // Retime
                p_regbank[r] <= param_in[(r+1)*pw-1: r*pw];
        end
end endgenerate

// Delay addrb to match dpram latency
reg [const_aw-1:0] rd_addr_r;
always @(posedge sf_clk) rd_addr_r <= rd_addr;

assign rd_data = p_regbank[rd_addr_r];  // This is a multiplexer


sf_user #(.pw(pw), .extra(extra), .mw(mw), .data_len(data_len),
        .consts_len(consts_len), .const_aw(const_aw))
sf_user (
        .clk(sf_clk), .ce(ce), .meas(meas), .trigger(trigger),
        .h_addr(rd_addr), .h_data(rd_data),
        .ab_update(ab_update), .a_o(a_o), .b_o(b_o),
        .cd_update(cd_update), .c_o(c_o), .d_o(d_o),
        .trace(trace), .trace_addr(trace_addr), .trace_strobe(trace_strobe),
        .sat_count(sat_count));

endmodule

#!/usr/bin/python

n_given = 0
state_vars = {}


def cgen_init(name):
    print("// machine-generated by " + name)
    print("#define ZZZ")


def setup(a):
    v = "int"
    if a in state_vars:
        v = "ZZZ"
    return v+" "+a


def given(a):
    global n_given
    print(setup(a) + " = given[" + str(n_given) + "];")
    n_given += 1


def persist(a, init=0):
    print("static int " + a + ";  if (init) " + a + " = persist_get(\"" + a + "\");")
    state_vars[a] = 1


def cpx_persist(a, init=0):
    persist(a + "_r", init=init.real)
    persist(a + "_i", init=init.imag)


def comment(s):
    print("if (VERBOSE) printf(\""+s+"\\n\");")


def print_op2(op, out, a, b, shift):
    print(setup(out)+" = "+op+"("+a+", "+b+", "+str(shift)+");")


def inv(out, a, shift):
    print(setup(out)+" = inv("+a+", "+str(shift)+");")


def set_result(o, a, b):
    print("set_result_"+o+"("+a+", "+b+");")


# out = (a + b) * 2^{shift}
def add(out, a, b, shift):
    print_op2("add", out, a, b, shift)


# out = (a - b) * 2^{shift}
def sub(out, a, b, shift):
    print_op2("sub", out, a, b, shift)


# out = a
def copy(out, a):
    add(out, a, a, 0)


# out = a * b * 2^{shift}
def mul(out, a, b, shift):
    print_op2("mul", out, a, b, shift)


# out = (a + b) * 2^{shift-1}
def cpx_add(out, a, b, shift):
    add(out+"_r", a+"_r", b+"_r", shift)
    add(out+"_i", a+"_i", b+"_i", shift)
    comment("done with cpx_add")


# out = (a - b) * 2^{shift-1}
def cpx_sub(out, a, b, shift):
    sub(out+"_r", a+"_r", b+"_r", shift)
    sub(out+"_i", a+"_i", b+"_i", shift)
    comment("done with cpx_sub")


# out = a
def cpx_copy(out, a):
    copy(out+"_r", a+"_r")
    copy(out+"_i", a+"_i")


# out = a * b * 2^{shift+shift2-1}
def cpx_mul(out, a, b, shift, shift2):
    mul(out+"_t2", a+"_r", b+"_i", shift)
    mul(out+"_t3", a+"_i", b+"_r", shift)
    mul(out+"_t1", a+"_r", b+"_r", shift)
    mul(out+"_t4", a+"_i", b+"_i", shift)
    add(out+"_i", out+"_t2", out+"_t3", shift2)
    sub(out+"_r", out+"_t1", out+"_t4", shift2)
    comment("done with cpx_mul")


# out = a * conj(b) * 2^{shift+shift2-1}
def cpx_mul_conj(out, a, b, shift, shift2):
    mul(out+"_t2", a+"_r", b+"_i", shift)
    mul(out+"_t3", a+"_i", b+"_r", shift)
    mul(out+"_t4", a+"_i", b+"_i", shift)
    mul(out+"_t1", a+"_r", b+"_r", shift)
    sub(out+"_i", out+"_t3", out+"_t2", shift2)
    add(out+"_r", out+"_t1", out+"_t4", shift2)
    comment("done with cpx_mul_conj")


# out = a * a * 2^{shift}
def cpx_sqr(out, a, shift):
    mul(out+"_t2", a+"_i", a+"_i", shift)
    mul(out+"_t1", a+"_r", a+"_r", shift)
    mul(out+"_i", a+"_r", a+"_i", shift+1)
    sub(out+"_r", out+"_t1", out+"_t2", 1)
    comment("done with cpx_sqr")


# out = a * conj(a) * 2^{shift}
def cpx_mag(out, a, shift):
    mul(out+"_t2", a+"_i", a+"_i", shift)
    mul(out+"_t1", a+"_r", a+"_r", shift)
    add(out, out+"_t1", out+"_t2", 1)


# out = Re( a * b ) * 2^{shift}
def cpx_dot(out, a, b, shift):
    mul(out+"_t2", a+"_i", b+"_i", shift)
    mul(out+"_t1", a+"_r", b+"_r", shift)
    add(out, out+"_t1", out+"_t2", 1)


# out = a * b * 2^{shift}   (b is the scalar)
def cpx_scale(out, a, b, shift):
    mul(out+"_r", a+"_r", b, shift)
    mul(out+"_i", a+"_i", b, shift)
    comment("done with cpx_scale")


# one iteration of iterative refinement of 1/a (prev is the previous estimate)
def inv_iter(out, a, prev):
    mul(out+"_e", prev, a, 3)
    sub(out+"_f", "two", out+"_e", 3)
    mul(out, prev, out+"_f", 3)


# out = 2^{-8}/a
# Carefully tuned interaction between the inv primitive,
# inv_iter, and the constant value "two"
# Accuracy is mediocre at the moment (0.4%), could either add resolution
# to inv primitive, or add another inv_iter cycle.
def full_inv(out, a):
    inv(out+"_guess", a, 0)
    inv_iter(out+"_r1", a, out+"_guess")
    inv_iter(out, a, out+"_r1")
    comment("done with full_inv")


# out = conj(1/a) * 2^{shift2-8-shift}
# probably want to keep shift as 0
def cpx_inv_conj(out, a, shift, shift2):
    mul(out+"_r1", a+"_r", a+"_r", shift)
    mul(out+"_r2", a+"_i", a+"_i", shift)
    add(out+"_m", out+"_r1", out+"_r2", 1)
    full_inv(out+"_s", out+"_m")
    mul(out+"_r", out+"_s", a+"_r", shift2)
    mul(out+"_i", out+"_s", a+"_i", shift2)
    comment("done with cpx_inv_conj")


# out = a / ( b^2 * conj(c) )
# scaling is probably messed up
def cpx_triad(out, a, b, c):
    cpx_sqr(out+"_t1", b, 1)
    cpx_mul_conj(out+"_t2", out+"_t1", c, 2, 1)
    cpx_inv_conj(out+"_t3", out+"_t2", 0, 0)
    cpx_mul_conj(out, a, out+"_t3", 2, 1)
    comment("done with cpx_triad")

#!/usr/bin/python

from re import search
from sys import argv

# list of variables, pointing to the operation that sources it
pipe_len = 5
source = {}
n_count = 0   # only used to summarize scheduling performance
pc_in_use = {}  # points to instruction instance
max_pc = 0
verbose = False   # can set to True for more verbose output, still compiles

# two things we need to know about a "variable"
becomes_valid = {}
last_used = {}
state_vars = {}   # need to be kept around forever


def tobin(x, count=8):
    # Integer to binary; count is number of bits
    # Credit to W.J. van der Laan in https://code.activestate.com/recipes/219300/
    return "".join([str((x >> y) & 1) for y in range(count-1, -1, -1)])


def next_avail(n):
    while n in pc_in_use:
        n += 1
    return n


def new_state_var(a):
    state_vars[a] = True
    becomes_valid[a] = 0


class afunc:
    def __init__(self, lhs, op, shift, args):
        self.lhs = lhs
        self.op = op
        self.shift = shift
        global n_count, max_pc, source, pipe_len
        n_count = n_count+1
        pc0 = 0
        source[lhs] = self
        self.args = args
        if lhs in state_vars and lhs in last_used:
            pc0 = last_used[lhs]
        for a in args:
            if a != lhs and pc0 < becomes_valid[a]:
                pc0 = becomes_valid[a]
        pc = next_avail(pc0)
        # print("// %s arglist (%s) pc %d -> %d" % (op, args, pc0, pc))
        self.pc = pc
        pc_in_use[pc] = self
        if pc > max_pc:
            max_pc = pc
        becomes_valid[lhs] = pc+pipe_len
        for a in args:
            if a != lhs and (a not in last_used or last_used[a] < pc):
                last_used[a] = pc

    def text(self):
        return "%s = %s(%s) << %d" % (self.lhs, self.op, ", ".join(self.args), self.shift)


def oplist(ov, fn, args):
    # print("oplist (%s) (%s) (%s)" % (ov, fn, args))
    x = [xx.strip() for xx in args.split(",")]
    shift = int(x.pop())
    afunc(ov, fn, shift, x)


def given(ov, sl):
    new_op = afunc(ov, "inp", 0, [])
    print("// given(%s, %s) pc=%d" % (ov, sl, new_op.pc))


def unmatched(line):
    print("// unmatched: " + line)


ifile = open(argv[1], 'r')
fdata = ifile.read()
print("// machine-generated by sched.py")
for line in fdata.split('\n'):
    if line.strip() and line.find("printf") != 0:
        if line[0:2] == "//":
            print(line)
            continue
        m1 = search(r"^ *(\w+) +([^ ]+) *= *(\w+)\((.*)\);", line)
        m2 = search(r"^ *(\w+) +([^ ]+) *= *given\[(\d+)\];", line)
        m3 = search(r"^ *set_result_([a-z]*)\((.*)\);", line)
        m4 = search(r"^ *static +int +(\w+);", line)
        if m1:
            de = m1.group(1)
            ov = m1.group(2)
            fn = m1.group(3)
            args = m1.group(4)
            if de == "int" or de == "ZZZ":
                oplist(ov, fn, args)
            else:
                unmatched(line)
        elif m2:
            de = m2.group(1)
            ov = m2.group(2)
            sl = m2.group(3)
            if de == "int" or de == "ZZZ":
                given(ov, sl)
            else:
                unmatched(line)
        elif m3:
            de = m3.group(1)  # should be ab or cd
            args = m3.group(2)
            oplist("terminus", "set_"+de, args+",0")
        elif m4:
            sv = m4.group(1)
            print("// state_var " + sv)
            new_state_var(sv)
        else:
            unmatched(line)

print("// %d instructions, %d highest pc in use" % (n_count, max_pc))

# Special case adjustment applies to state variables, that have to persist.
# It's important that this adjustment happens after instruction scheduling,
# but before register mapping.
for var in state_vars:
    becomes_valid[var] = 0
    last_used[var] = max_pc

regmap = {}
reg_assign = {}
reg_assign["terminus"] = 0  # maybe a mistake
highest_regnum = 0
cross_ref = {}


def regmap_entry(reg, n):
    return "%d:%d" % (reg, n) in regmap


def regmap_mark(reg, n):
    regmap["%d:%d" % (reg, n)] = 1


def regmap_range(v):
    return list(range(becomes_valid[v], last_used[v]+1))


def blacklist_reg(v, reg):
    for n in regmap_range(v):
        regmap_mark(reg, n)


def compat(v, reg):
    for n in regmap_range(v):
        if regmap_entry(reg, n):
            return 0
    return 1


def choose_reg(v):
    for n in range(1, 31):
        if compat(v, n):
            reg_assign[v] = n
            if n in cross_ref:
                cross_ref[n].append(v)
            else:
                cross_ref[n] = [v]
            blacklist_reg(v, n)
            global highest_regnum
            if n > highest_regnum:
                highest_regnum = n
            return n
    print("error: no space in register file for %s" % v)
    exit(1)


def assign_vars():
    for v in sorted(becomes_valid.keys()):
        if v in last_used:
            n = choose_reg(v)
            if verbose:
                print("// assigned %d for %s from %d to %d" % (n, v, becomes_valid[v], last_used[v]))
        else:
            print("// %s from %d never used" % (v, becomes_valid[v]))


def dump_regmap():
    print("// register blackout map")
    for n in range(0, max_pc+1):
        ss = "//  %3d:" % n
        for m in range(0, 31):
            ss = ss + (" X" if regmap_entry(m, n) else "  ")
        print(ss)


def show_xref():
    print("// register cross-reference")
    for n in sorted(cross_ref.keys()):
        print("//  %2d: %s" % (n, " ".join(cross_ref[n])))


assign_vars()
if verbose:
    dump_regmap()
show_xref()
print("// %d abstract results packed into %d registers" % (len(becomes_valid), highest_regnum))
print("// one instruction, as broken into pipeline stages:")
print("//                .  .  .    .   bbbbb aaaaa")
print("//                .  . ooo   .     .     .")
print("//                . ss  .    .     .     .")
print("//                .  .  .    .     .     .")
print("//                t  .  .  wwwww   .     .        symbolic form")

stream_ra = {}
stream_rb = {}
stream_wa = {}
stream_op = {}
stream_sv = {}
stream_st = {}

opcodes = {'nop': 0, 'inp': 0, 'set_ab': 1, 'set_cd': 2, 'mul': 4, 'inv': 5, 'add': 6, 'sub': 7}


def emit(pc, lhs, op, shift, a, b):
    # print("// %d: %d = %s (%d, %d) << %d" % (pc, lhs, op, a, b, shift))
    # note the pipelining encoded here, matches sf_main.v and the
    # graphic printed above as comments.
    stream_ra[pc-4] = a
    stream_rb[pc-4] = b
    stream_op[pc-3] = opcodes[op]
    stream_sv[pc-2] = shift
    stream_wa[pc-0] = lhs
    stream_st[pc-0] = op == "inp"


for pc in range(0, max_pc+6):
    if pc in pc_in_use:
        inst = pc_in_use[pc]
        aa = []
        for a in inst.args:
            aa.append(reg_assign[a])
        if inst.op == "inv":
            aa.append(0)
        if inst.op == "inp":
            aa.append(0)
            aa.append(0)
        emit(pc, reg_assign[inst.lhs], inst.op, inst.shift, aa[0], aa[1])
    else:
        emit(pc, 0, "nop", 0, 0, 0)


print("// inst coding:  st sv  op   wa    rb    ra")
for pc in range(0, max_pc+1):
    if pc in pc_in_use:
        comment = "  // " + pc_in_use[pc].text()
    else:
        comment = ""
    inst_p = tobin(stream_st[pc], 1) + "_" + \
        tobin(stream_sv[pc], 2) + "_" + \
        tobin(stream_op[pc], 3) + "_" + \
        tobin(stream_wa[pc], 5) + "_" + \
        tobin(stream_rb[pc], 5) + "_" + \
        tobin(stream_ra[pc], 5)
    print("%4d: inst <= 21'b%s;%s" % (pc, inst_p, comment))


print("default: inst <= 0;")

